// COMPLETE, COMPILABLE C code
#include <stdio.h>
int main() {
    int N, Q;
    scanf("%d", &N);
    int A[N], B[N];
    for (int i = 0; i < N; i++) {
        scanf("%d %d", &A[i], &B[i]);
    }
    scanf("%d", &Q);
    for (int i = 0; i < Q; i++) {
        int type;
        scanf("%d", &type);
        if (type == 1) {
            int i, j;
            scanf("%d %d", &i, &j);
            int sum = 0;
            for (int k = i-1; k < j; k++) {
                sum += A[k] + B[k];
            }
            printf("%d\n", sum);
        } else if (type == 2) {
            int L, R, x;
            scanf("%d %d %d", &L, &R, &x);
            for (int k = L-1; k < R; k++) {
                B[k] = x;
            }
            int sum = 0;
            for (int k = 0; k < N; k++) {
                sum += A[k] + B[k];
            }
            printf("%d\n", sum);
        }
    }
    return 0;
}

