public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int[] A = new int[N];
        int[] B = new int[N];
        for (int i = 0; i < N; i++) {
            A[i] = sc.nextInt();
            B[i] = sc.nextInt();
        }
        int Q = sc.nextInt();
        for (int i = 0; i < Q; i++) {
            int type = sc.nextInt();
            if (type == 1) {
                int i1 = sc.nextInt();
                int j = sc.nextInt();
                int sum = 0;
                for (int k = i1-1; k < j; k++) {
                    sum += A[k] + B[k];
                }
                System.out.println(sum);
            } else if (type == 2) {
                int L = sc.nextInt();
                int R = sc.nextInt();
                int x = sc.nextInt();
                for (int k = L-1; k < R; k++) {
                    B[k] = x;
                }
                int sum = 0;
                for (int k = 0; k < N; k++) {
                    sum += A[k] + B[k];
                }
                System.out.println(sum);
            }
        }
    }
